def esc(s):
    return s.replace("'", "\\'")

def gen_items(prefix, items_list):
    lines = []
    n = len(items_list)
    for i, (ch, name, content) in enumerate(items_list, 1):
        comma = ',' if i < n else ''
        lines.append(f"        {{ id: '{prefix}-g3-{i}', chapter: '{esc(ch)}', name: '{esc(name)}', content: '{esc(content)}' }}{comma}")
    return '\n'.join(lines)

